import { useContext, useEffect, useMemo, useState } from "react";
import { AuthContext } from "./AuthContext";
import "./styles/club_header.css";
import ClubHeader from "./ClubHeader";

/* =======================
   TAB COMPONENTS
   ======================= */

function ClubOverview({ club }) {
    return (
        <div style={s.card}>
            <h3>About</h3>
            <p>{club.description || "No description provided."}</p>
        </div>
    );
}

function ClubNewsTab({ news, canPostNews, title, setTitle, content, setContent, postNews, deleteNews }) {
    return (
        <>
            {canPostNews && (
                <form onSubmit={postNews} style={s.card}>
                    <input
                        placeholder="Title"
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                        style={s.input}
                        required
                    />
                    <textarea
                        placeholder="Content"
                        value={content}
                        onChange={(e) => setContent(e.target.value)}
                        style={s.textarea}
                        required
                    />
                    <div style={{ textAlign: "right" }}>
                        <button style={s.primaryBtn}>Post</button>
                    </div>
                </form>
            )}

            {news.length === 0 && <div style={s.card}>No news yet.</div>}

            {news.map(n => (
                <div key={n.id} style={s.card}>
                    <strong>{n.title}</strong>
                    <p style={{ whiteSpace: "pre-wrap" }}>{n.content}</p>
                    <div style={s.meta}>
                        {new Date(n.createdAt).toLocaleString()}
                    </div>
                    {canPostNews && (
                        <button style={s.dangerBtn} onClick={() => deleteNews(n.id)}>
                            Delete
                        </button>
                    )}
                </div>
            ))}
        </>
    );
}

function ClubMembersTab({ members }) {
    return (
        <div style={s.card}>
            <h3>Members</h3>
            {members.length === 0 && <div>No members yet.</div>}
            <ul>
                {members.map(m => (
                    <li key={m.id}>
                        User #{m.userId} — <strong>{m.role}</strong>
                    </li>
                ))}
            </ul>
        </div>
    );
}

/* =======================
   MAIN COMPONENT
   ======================= */

export default function ClubDetail() {
    const { user } = useContext(AuthContext);

    /* ---- Route parsing ---- */
    const route = (() => {
        const m = (window.location.hash || "").match(/^#\/clubs\/(\d+)(?:\/(\w+))?/i);
        return {
            clubId: m ? Number(m[1]) : null,
            tab: m?.[2] || "overview",
        };
    })();

    const { clubId, tab: activeTab } = route;

    /* ---- State ---- */
    const [club, setClub] = useState(null);
    const [news, setNews] = useState([]);
    const [members, setMembers] = useState([]);
    const [title, setTitle] = useState("");
    const [content, setContent] = useState("");

    /* ---- Permissions ---- */
    const isAdmin = user?.role === "ADMIN";
    const isLeader = members.some(m => m.userId === user?.id && m.role === "LEADER");
    const canPostNews = isAdmin || isLeader;

    /* ---- Fetch data ---- */
    useEffect(() => {
        if (!clubId) return;

        fetch(`/api/clubs/${clubId}`).then(r => r.json()).then(setClub);
        fetch(`/api/clubs/${clubId}/news`).then(r => r.json()).then(setNews);
        fetch(`/api/clubs/${clubId}/members`).then(r => r.json()).then(setMembers);
    }, [clubId]);

    /* ---- Tab registry (IMPORTANT) ---- */
    const TAB_COMPONENTS = {
        overview: ClubOverview,
        news: ClubNewsTab,
        members: ClubMembersTab,
    };

    const enabledTabs = club?.enabledTabs || ["overview", "news", "members"];

    const safeTab = enabledTabs.includes(activeTab)
        ? activeTab
        : "overview";

    const ActiveTab = TAB_COMPONENTS[safeTab];

    /* ---- Actions ---- */
    const postNews = async (e) => {
        e.preventDefault();
        const res = await fetch(
            `/api/clubs/${clubId}/news?requesterEmail=${encodeURIComponent(user.email)}`,
            {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ title, content }),
            }
        );
        const body = await res.json();
        setNews(prev => [body, ...prev]);
        setTitle("");
        setContent("");
    };

    const deleteNews = async (id) => {
        await fetch(
            `/api/clubs/${clubId}/news/${id}?requesterEmail=${encodeURIComponent(user.email)}`,
            { method: "DELETE" }
        );
        setNews(prev => prev.filter(n => n.id !== id));
    };

    if (!club) return <div style={s.card}>Loading…</div>;

    /* ---- Leaders ---- */
    const leaders = members
        .filter(m => m.role === "LEADER")
        .map(m => `User #${m.userId}`);

    return (
        <div className="page">
            <ClubHeader
                club={club}
                leaders={leaders}
                activeTab={safeTab}
                membership={{
                    isMember: members.some(m => m.userId === user?.id),
                    hasPending: false,
                    isLeader,
                }}
                onJoin={() => {}}
                onLeave={() => {}}
                onCancelRequest={() => {}}
            />

            <div style={s.grid}>
                <ActiveTab
                    club={club}
                    news={news}
                    members={members}
                    canPostNews={canPostNews}
                    title={title}
                    setTitle={setTitle}
                    content={content}
                    setContent={setContent}
                    postNews={postNews}
                    deleteNews={deleteNews}
                />
            </div>
        </div>
    );
}

/* =======================
   STYLES
   ======================= */

const s = {
    grid: { padding: 16 },
    card: {
        background: "#fff",
        borderRadius: 10,
        padding: 16,
        marginBottom: 12,
        boxShadow: "0 4px 14px rgba(0,0,0,0.08)",
    },
    input: {
        width: "100%",
        padding: 8,
        marginBottom: 8,
    },
    textarea: {
        width: "100%",
        minHeight: 100,
        padding: 8,
        marginBottom: 8,
    },
    primaryBtn: {
        background: "#0b57d0",
        color: "#fff",
        border: "none",
        padding: "8px 12px",
        borderRadius: 6,
        cursor: "pointer",
    },
    dangerBtn: {
        background: "#b00020",
        color: "#fff",
        border: "none",
        padding: "6px 10px",
        borderRadius: 6,
        cursor: "pointer",
    },
    meta: {
        fontSize: 12,
        opacity: 0.6,
        marginTop: 4,
    },
};
